+/**
+ * User notification preferences model.
+ *
+ * Controls how and when a user receives notifications.
+ * Currently supports email as the only channel.
+ * Designed to be extensible for future channels (SMS, in-app, webhook).
+ */
+
+import type { NotificationType } from './notification.js';
+
+/**
+ * Email frequency options controlling how often email digests are sent.
+ * - 'instant': Send emails immediately as events occur
+ * - 'daily': Batch into a daily digest
+ * - 'weekly': Batch into a weekly digest
+ * - 'never': Do not send emails
+ */
+export type EmailFrequency = 'instant' | 'daily' | 'weekly' | 'never';
+
+/**
+ * Per-channel notification settings.
+ * Currently only email is implemented.
+ */
+export interface EmailNotificationSettings {
+  enabled: boolean;
+  frequency: EmailFrequency;
+  subscribedCategories: NotificationType[];
+}
+
+/**
+ * Full user notification preferences.
+ */
+export interface UserPreferences {
+  id: string;
+  userId: string;
+  email: EmailNotificationSettings;
+  createdAt: Date;
+  updatedAt: Date;
+}
+
+/**
+ * Input for creating user preferences.
+ */
+export interface CreateUserPreferencesInput {
+  userId: string;
+  email?: Partial<EmailNotificationSettings>;
+}
+
+/**
+ * Input for updating user preferences.
+ */
+export interface UpdateUserPreferencesInput {
+  email?: Partial<EmailNotificationSettings>;
+}
+
+/**
+ * All supported notification categories.
+ */
+export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
+  'order_confirmation',
+  'order_status_update',
+  'welcome',
+  'account_updated',
+];
+
+/**
+ * Default email notification settings for new users.
+ */
+export const DEFAULT_EMAIL_SETTINGS: EmailNotificationSettings = {
+  enabled: true,
+  frequency: 'instant',
+  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
+};

