/**
 * Dispatch a notification payload to the appropriate adapter.
 * Checks user preferences before sending. Records the notification and its delivery result.
 */
async dispatch(payload: NotificationPayload): Promise<NotificationResult> {
  const id = generateNotificationId();

  // Check user preferences before sending
  if (this.preferencesService && payload.channel === 'email') {
    const userId = (payload.metadata?.userId as string) ?? payload.recipient;
    if (!this.preferencesService.shouldSendEmail(userId, payload.type)) {
      this.logger.info(`Notification ${id} suppressed by user preferences for ${userId}`);
      const notification: Notification = {
        id,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        channel: payload.channel,
        type: payload.type,
        status: 'failed',
        metadata: payload.metadata,
        createdAt: new Date(),
      };
      this.notifications.push(notification);
      return { success: false, notificationId: id, channel: payload.channel, error: 'Suppressed by user preferences' };
    }
  }

  const notification: Notification = {
    id,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel: payload.channel,
    type: payload.type,
    status: 'pending',
    metadata: payload.metadata,
    createdAt: new Date(),
  };

  const adapter = this.adapters.get(payload.channel);
  if (!adapter) {
    this.logger.warn(`No adapter registered for channel: ${payload.channel}`);
    notification.status = 'failed';
    this.notifications.push(notification);
    return { success: false, notificationId: id, channel: payload.channel, error: `No adapter for channel: ${payload.channel}` };
  }

  const result = await adapter.send(payload);
  result.notificationId = id;

  notification.status = result.success ? 'sent' : 'failed';
  if (result.success) {
    notification.sentAt = new Date();
  }
  this.notifications.push(notification);

  this.logger.info(`Notification ${id} ${notification.status} via ${payload.channel}`);
  return result;
}

