import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
import { ALL_NOTIFICATION_CATEGORIES, DEFAULT_EMAIL_SETTINGS } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let prefsRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    prefsRepo = new PreferencesRepository(db);
    service = new PreferencesService(prefsRepo);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create default preferences for a user', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('instant');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          frequency: 'daily',
          subscribedCategories: ['order_confirmation'],
        },
      });

      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should throw if preferences already exist for the user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createPreferences({ userId: 'user-1' });
      const p2 = service.createPreferences({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });

    it('should use default categories when only partial email settings provided', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'weekly' },
      });

      expect(prefs.email.frequency).toBe('weekly');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.subscribedCategories).toEqual(DEFAULT_EMAIL_SETTINGS.subscribedCategories);
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for a user', () => {
      service.createPreferences({ userId: 'user-1' });
      const prefs = service.getPreferences('user-1');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });

    it('should return undefined if no preferences exist', () => {
      expect(service.getPreferences('nonexistent')).toBeUndefined();
    });
  });

  describe('updatePreferences', () => {
    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true);
      expect(updated.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update subscribed categories', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['welcome', 'order_confirmation'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['welcome', 'order_confirmation']);
    });

    it('should disable email notifications', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
    });

    it('should throw if preferences do not exist', () => {
      expect(() =>
        service.updatePreferences('nonexistent', { email: { enabled: false } }),
      ).toThrow('Preferences not found for user: nonexistent');
    });

    it('should update the updatedAt timestamp', () => {
      const created = service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'weekly' },
      });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(created.updatedAt.getTime());
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });
      const result = service.deletePreferences('user-1');

      expect(result).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false if preferences do not exist', () => {
      expect(service.deletePreferences('nonexistent')).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (default behavior)', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['welcome'],
        },
      });
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should return false when email disabled even if category is subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: false,
          subscribedCategories: ALL_NOTIFICATION_CATEGORIES,
        },
      });
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('getAvailableCategories', () => {
    it('should return all notification categories', () => {
      const categories = service.getAvailableCategories();
      expect(categories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return a copy, not the original array', () => {
      const categories = service.getAvailableCategories();
      categories.push('order_confirmation');
      expect(service.getAvailableCategories()).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);

    const prefsRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(prefsRepo);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  function makeOrderCreatedEvent(userId: string, email: string): OrderCreatedEvent {
    return {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: userId,
        name: 'Alice',
        email,
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };
  }

  function makeUserCreatedEvent(userId: string, email: string): UserCreatedEvent {
    return {
      type: 'user:created',
      user: {
        id: userId,
        name: 'Alice',
        email,
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };
  }

  it('should send notification when no preferences exist', async () => {
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('sent');
  });

  it('should send notification when user has email enabled and category subscribed', async () => {
    preferencesService.createPreferences({ userId: 'user-1' });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('sent');
  });

  it('should suppress notification when user has email disabled', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      email: { enabled: false },
    });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('failed');
  });

  it('should suppress notification when category is unsubscribed', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      email: {
        enabled: true,
        subscribedCategories: ['welcome'],
      },
    });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('failed');
  });

  it('should allow welcome but suppress order notifications based on category preferences', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      email: {
        enabled: true,
        subscribedCategories: ['welcome'],
      },
    });

    await eventBus.emit(makeUserCreatedEvent('user-1', 'alice@example.com'));
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(2);
    expect(notifications[0]?.type).toBe('welcome');
    expect(notifications[0]?.status).toBe('sent');
    expect(notifications[1]?.type).toBe('order_confirmation');
    expect(notifications[1]?.status).toBe('failed');
  });

  it('should return suppression error in result', async () => {
    preferencesService.createPreferences({
      userId: 'user-1',
      email: { enabled: false },
    });

    const result = await notificationService.dispatch({
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      channel: 'email',
      type: 'order_confirmation',
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(false);
    expect(result.error).toBe('Suppressed by user preferences');
  });
});
